#include <iostream>
#include <string>

int main() {
  int number = 42;
  double pi = 3.14;
  std::string message = "Hello, C++!";
  std::cout << "Number: " << number << std::endl;
  std::cout << "Pi: " << pi << std::endl;
  std::cout << "Message: " << message << std::endl;
  return 0;
}
// Output:
// Number: 42
// Pi: 3.14
// Message: Hello, C++!

#include <iostream>
#include <string>

class Car {
public:
  std::string brand = "Toyota";
  int speed = 120;

  void display() {
    std::cout << "Brand: " << brand << ", Speed: " << speed << " km/h" << std::endl;
  }
};

int main() {
  Car myCar;
  myCar.display();
  return 0;
}
// Output:
// Brand: Toyota, Speed: 120 km/h

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
  std::vector<int> numbers = {5, 2, 8, 1, 9};
  std::sort(numbers.begin(), numbers.end());
  std::cout << "Sorted numbers: ";
  for (int num : numbers) {
    std::cout << num << " ";
  }
  std::cout << std::endl;
  return 0;
}
// Output:
// Sorted numbers: 1 2 5 8 9

